#include <stdio.h>
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int dp[n + 1];
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        dp[i] = 1 + (i - m >= 0 ? dp[i - m] : (i - 1 >= 0 ? dp[i - 1] : 0));
    }
    printf("%d\n", dp[n]);
    return 0;
}

